import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Checkout({ user }) {
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const savedCart = JSON.parse(localStorage.getItem('cart')) || [];
    setCart(savedCart);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const total = cart.reduce((sum, item) => sum + item.price, 0);
    const order = {
      items: cart,
      total: total,
      user_name: user?.name,
      user_phone: user?.phone,
      user_department: user?.department,
      user_year: user?.year
    };

    try {
      await axios.post('/api/orders', order);
      localStorage.removeItem('cart');
      localStorage.setItem('orderData', JSON.stringify({
        order: order,
        user: user
      }));
      navigate('/bill');
    } catch (err) {
      console.error('Error placing order:', err);
      alert('Failed to place order. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const total = cart.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="checkout-container">
      <h2>📦 Checkout</h2>
      
      <div className="bill-section">
        <h3>Order Summary</h3>
        {cart.length === 0 ? (
          <p>Your cart is empty</p>
        ) : (
          cart.map((item, index) => (
            <div key={index} className="bill-row">
              <span>{item.name}</span>
              <span>₹{item.price}</span>
            </div>
          ))
        )}
      </div>

      <div className="bill-row total">
        <span>Total Amount:</span>
        <span>₹{total}</span>
      </div>

      <form onSubmit={handleSubmit} className="checkout-form">
        <h3>Delivery Details</h3>
        <input type="text" value={user?.name || ''} disabled placeholder="Name" />
        <input type="email" value={user?.phone || ''} disabled placeholder="Phone" />
        <input type="text" value={user?.department || ''} disabled placeholder="Department" />
        <input type="text" value={user?.year || ''} disabled placeholder="Year" />
        
        <button type="submit" disabled={loading || cart.length === 0}>
          {loading ? 'Placing Order...' : 'Place Order'}
        </button>
      </form>
    </div>
  );
}

export default Checkout;
